export const ELEMENTS_BY_SYMBOL: Record<string, Element> = Object.fromEntries(
  ELEMENTS.map((el) => [el.symbol, el]),
);

export const ELEMENTS_BY_NUMBER: Record<number, Element> = Object.fromEntries(
  ELEMENTS.map((el) => [el.n, el]),
);

export function findElement(query: string): Element | undefined {
  const q = query.trim().toLowerCase();
  if (!q) return undefined;
  return ELEMENTS.find(
    (el) =>
      el.symbol.toLowerCase() === q ||
      el.name.toLowerCase() === q ||
      el.nameEn.toLowerCase() === q ||
      el.n.toString() === q,
  );
}

export function filterElements(query: string): Element[] {
  const q = query.trim().toLowerCase();
  if (!q) return ELEMENTS;
  return ELEMENTS.filter(
    (el) =>
      el.symbol.toLowerCase().includes(q) ||
      el.name.toLowerCase().includes(q) ||
      el.nameEn.toLowerCase().includes(q) ||
      el.n.toString().includes(q),
  );
}
